-- DROP TABLE IF EXISTS games CASCADE;

CREATE TABLE games (id text NOT NULL, title text NOT NULL, price numeric, original_price numeric, discount integer, description text, long_description text, image text, genre jsonb, console text NOT NULL, rating numeric, featured boolean, in_stock boolean, release_date date, created_at timestamp with time zone, updated_at timestamp with time zone, account_options jsonb, url_yt text);

-- Constraints
ALTER TABLE games ADD CONSTRAINT games_pkey PRIMARY KEY (id);

