INSERT INTO games VALUES ('cc628fc47a46a3149b2ce167e594cbe5','Mortal kombat 11 Ultimate - PS4',0,169,0,'Mortal kombat 11 Ultimate Para PS4
A melhor experiência MK11 de sempre! Assume o controlo dos protetores do Earthrealm nas DUAS campanhas de história aclamadas e que atravessam os tempos, numa tentativa de deter Kronika que pretende fazer recuar o tempo e reiniciar a História. As amizades são testadas e novas alianças são forjadas, numa batalha para salvar toda a existência.

 

