INSERT INTO games VALUES ('5021c28d7fee614364705564cac49dd6','Nickelodeon All-Star Brawl 2 - PS5',0,159,0,'Nickelodeon All-Star Brawl 2 Para PS5 
Nickelodeon All-Star Brawl 2 permite que você brigue com a maior e melhor lista de personagens de luta até agora, incluindo todos os novos personagens como Bob Esponja Calça Quadrada, As Tartarugas Ninja, Lula Molusco, Jimmy Neutron e muito mais!

 

